## Тћ╣тќё№╝џCodedErrorсЃЉсѓ┐сЃ╝сЃ│сЂ«т░јтЁЦ

sentinel errorсѓњуХГТїЂсЂЌсЂцсЂцсђЂ**сѓесЃЕсЃ╝сѓ│сЃ╝сЃЅсЂеHTTPсѓ╣сЃєсЃ╝сѓ┐сѓ╣сѓњухёсЂ┐УЙ╝сѓЊсЂаCodedErrorтъІ**сѓњт░јтЁЦсЂЌсЂЙсЂЌсЂЪсђѓ

```go
// pkg/apperror/coded_error.go
package apperror

import "net/http"

type CodedError struct {
    code       string
    message    string
    httpStatus int
}

func (e *CodedError) Error() string {
    return e.message
}

func (e *CodedError) Code() string       { return e.code }
func (e *CodedError) HTTPStatus() int    { return e.httpStatus }

func newCodedError(code, message string, status int) *CodedError {
    return &CodedError{
        code:       code,
        message:    message,
        httpStatus: status,
    }
}
```

сѓесЃЕсЃ╝сѓњсѓФсЃєсѓ┤сЃфсЂћсЂесЂФт«џуЙЕсЂЌсЂЙсЂЎсђѓ

```go
// pkg/apperror/codes.go
var (
    // сЃљсЃфсЃЄсЃ╝сѓисЃДсЃ│у│╗№╝ѕ400№╝Ѕ
    ErrInvalidFormat = newCodedError("VAL001", "invalid format", http.StatusBadRequest)
    ErrDuplicateEntry = newCodedError("VAL002", "duplicate entry", http.StatusBadRequest)

    // уФХтљѕу│╗№╝ѕ409№╝Ѕ
    ErrAlreadyRunning = newCodedError("CONF001", "resource is already running", http.StatusConflict)

    // УфЇУе╝сЃ╗УфЇтЈ»у│╗
    ErrAuthRequired = newCodedError("AUTH001", "authentication required", http.StatusUnauthorized)
    ErrForbidden    = newCodedError("AUTH002", "permission denied", http.StatusForbidden)

    // сЃфсѓйсЃ╝сѓ╣у│╗№╝ѕ404№╝Ѕ
    ErrNotFound = newCodedError("RES001", "resource not found", http.StatusNotFound)

    // тєЁжЃесѓесЃЕсЃ╝у│╗№╝ѕ500№╝Ѕ
    ErrInternal = newCodedError("SYS001", "internal error", http.StatusInternalServerError)
)
```

### Handlerт▒цсЂїсѓисЃ│сЃЌсЃФсЂФсЂфсѓІ

CodedErrorсѓњт░јтЁЦсЂЌсЂЪсЂЊсЂесЂДсђЂHandlerт▒цсЂ«сѓесЃЕсЃ╝тЄдуљєсѓњ**1у«ЄТЅђсЂФжЏєу┤ё**сЂДсЂЇсЂЙсЂЌсЂЪсђѓ

```go
// interface/rest/handler/error_handler.go
func HandleError(w http.ResponseWriter, err error) {
    var coded *apperror.CodedError
    if errors.As(err, &coded) {
        writeJSON(w, coded.HTTPStatus(), ErrorResponse{
            Code:    coded.Code(),
            Message: coded.Error(),
        })
        return
    }

    // CodedErrorсЂДсЂфсЂёсѓесЃЕсЃ╝сЂ»сЂЎсЂ╣сЂдтєЁжЃесѓесЃЕсЃ╝
    slog.Error("unhandled error", "error", err)
    writeJSON(w, http.StatusInternalServerError, ErrorResponse{
        Code:    "SYS999",
        Message: "тєЁжЃесѓесЃЕсЃ╝сЂїуЎ║ућЪсЂЌсЂЙсЂЌсЂЪ",
    })
}
```

```go
// Handlerт▒цсЂ» err сѓњТИАсЂЎсЂасЂЉ
func (h *JobHandler) CreateJob(w http.ResponseWriter, r *http.Request) {
    result, err := h.createJob.Execute(r.Context(), input)
    if err != nil {
        HandleError(w, err)
        return
    }
    writeJSON(w, http.StatusCreated, result)
}
```

сЂЊсѓїсЂФсѓѕсѓісђЂifТќЄсЂ«тѕєт▓љсЂїсЂфсЂЈсЂфсѓісЂЙсЂЌсЂЪсђѓ`HandleError`сЂ»`errors.As`сЂД**тъІ**№╝ѕ`*CodedError`№╝Ѕсѓњтѕцт«џсЂЌсЂдсЂёсЂЙсЂЎсђѓ`errors.Is`сЂ«сѓѕсЂєсЂф**тђц**сЂ«Т»ћУ╝ЃсЂДсЂ»сЂфсЂёсЂЪсѓЂсђЂсЂЕсЂ«`CodedError`сЂДсѓѓтљїсЂўтЄдуљєсЂДТЅ▒сЂѕсЂЙсЂЎсђѓжђєсЂФУеђсЂѕсЂ░сђЂ`errors.Is(err, apperror.ErrNotFound)`сЂ«сѓѕсЂєсЂфтђцсЂДсЂ«тѕцт«џсЂ»сЂДсЂЇсЂЙсЂЏсѓЊсђѓуЅ╣т«џсЂ«сѓесЃЕсЃ╝уе«тѕЦсѓњтї║тѕЦсЂЌсЂЪсЂёта┤тљѕсЂ»сђЂ`Code()`сЃАсѓйсЃЃсЃЅсЂДтѕцт«џсЂЌсЂдсЂЈсЂасЂЋсЂёсђѓ

---

## сЃЅсЃАсѓцсЃ│сѓесЃЕсЃ╝сЂеCodedErrorсЂ«Сй┐сЂётѕєсЂЉ

сЃЅсЃАсѓцсЃ│т▒цсЂДсЂ»sentinel errorсѓњСй┐сЂёсђЂсѓбсЃЌсЃфсѓ▒сЃ╝сѓисЃДсЃ│т▒ц№╝ѕInteractor№╝ЅсЂДCodedErrorсЂФтцЅТЈЏсЂЌсЂЙсЂЎсђѓ

```go
// domain/model/errors.go№╝ѕтцЅТЏ┤сЂфсЂЌ№╝Ѕ
var (
    ErrTaskAlreadyRunning = errors.New("another task is already running")
    ErrInvalidCSVFormat   = errors.New("invalid CSV format")
)
```

```go
// usecase/create_job_interactor.go
func (i *CreateJobInteractor) Execute(ctx context.Context, req *CreateJobInput) (*CreateJobOutput, error) {
    // сЃљсЃфсЃЄсЃ╝сѓисЃДсЃ│№╝ѕу░АуЋЦтїќсЂ«сЂЪсѓЂТ▒јућесѓесЃЕсЃ╝сѓњУ┐ћсЂЌсЂдсЂёсѓІ№╝Ѕ
    if err := i.validateInput(req); err != nil {
        return nil, apperror.ErrInvalidFormat  // CodedError
    }
    // NOTE: т«ЪжџЏсЂ«APIсЂДсЂ»сђїсЂЕсЂ«сЃЋсѓБсЃ╝сЃФсЃЅсЂїСИЇТГБсЂІсђЇсѓњсѓ»сЃЕсѓцсѓбсЃ│сЃѕсЂФУ┐ћсЂЎт┐ЁУдЂсЂїсЂѓсѓісЂЙсЂЎсђѓ
    // сЃЋсѓБсЃ╝сЃФсЃЅсЃгсЃЎсЃФсЂ«сЃљсЃфсЃЄсЃ╝сѓисЃДсЃ│сѓесЃЕсЃ╝сЂ» CodedError сѓњТІАт╝хсЂЌсЂд details сЃЋсѓБсЃ╝сЃФсЃЅсѓњ
    // ТїЂсЂЪсЂЏсѓІсЂІсђЂт░ѓућесЂ« ValidationError тъІсѓњт«џуЙЕсЂЎсѓІсЂ«сЂїт«ЪУихуџёсЂДсЂЎсђѓ

    // ТјњС╗ќсЃЂсѓДсЃЃсѓ»
    running, err := i.jobRepo.ExistsPendingOrProcessing(ctx)
    if err != nil {
        return nil, fmt.Errorf("failed to check running jobs: %w", err)  // сѓцсЃ│сЃЋсЃЕсѓесЃЕсЃ╝
    }
    if running {
        return nil, apperror.ErrAlreadyRunning  // CodedError
    }

    // сЃЅсЃАсѓцсЃ│сѓфсЃќсѓИсѓДсѓ»сЃѕућЪТѕљ
    job := model.NewImportJob(req.Data, req.WebhookURL)
    if err := i.jobRepo.Save(ctx, job); err != nil {
        return nil, fmt.Errorf("failed to save job: %w", err)  // сѓцсЃ│сЃЋсЃЕсѓесЃЕсЃ╝
    }

    return &CreateJobOutput{JobID: job.ID}, nil
}
```

### сЂфсЂюсЃЅсЃАсѓцсЃ│т▒цсЂ»sentinel errorсЂ«сЂЙсЂЙсЂфсЂ«сЂІ

сЃЅсЃАсѓцсЃ│т▒цсЂ»**HTTPсѓ╣сЃєсЃ╝сѓ┐сѓ╣сѓёсѓесЃЕсЃ╝сѓ│сЃ╝сЃЅсѓњуЪЦсѓІсЂ╣сЂЇсЂДсЂ»сЂфсЂё**сЂІсѓЅсЂДсЂЎсђѓсЃЅсЃАсѓцсЃ│сЂ«жќбт┐ЃС║ІсЂ»сђїсЃЊсѓИсЃЇсѓ╣сЃФсЃ╝сЃФжЂЋтЈЇсЂїУхисЂЇсЂЪсЂЊсЂесђЇсЂДсЂѓсѓісђЂHTTP 400сѓё409сЂИсЂ«тцЅТЈЏсЂ»сЃЌсЃгсѓ╝сЃ│сЃєсЃ╝сѓисЃДсЃ│сЂ«У▓гтІЎсЂДсЂЎсђѓ

сЃЅсЃАсѓцсЃ│т▒цсЂ«sentinel errorсЂ»сђЂInteractorт▒цсЂДCodedErrorсЂФтцЅТЈЏсЂЋсѓїсЂЙсЂЎсђѓ

```go
// usecase/get_job_interactor.go
func (i *GetJobInteractor) Execute(ctx context.Context, id string) (*GetJobOutput, error) {
    job, err := i.repo.FindByID(ctx, id)
    if err != nil {
        if errors.Is(err, model.ErrTaskNotFound) {
            return nil, apperror.ErrNotFound  // sentinel Рєњ CodedError
        }
        return nil, fmt.Errorf("failed to get job: %w", err)
    }
    return &GetJobOutput{Job: job}, nil
}
```

`errors.Is`сЂДsentinel errorсѓњтѕцт«џсЂЌсђЂт»Йт┐юсЂЎсѓІ`CodedError`сѓњУ┐ћсЂЌсЂЙсЂЎсђѓ

