## Уф▓жАї№╝џHandlerт▒цсЂДсЂ«тѕєт▓љсЂїуѕєуЎ║сЂЌсЂЪ

сЃЌсЃГсѓИсѓДсѓ»сЃѕсЂїТѕљжЋисЂЎсѓІсЂФсЂцсѓїсђЂHandlerт▒цсЂ«сѓесЃЕсЃ╝тЄдуљєсЂїсЂЊсЂєсЂфсѓісЂЙсЂЌсЂЪсђѓ

```go
// РЮї Handlerт▒цсЂДsentinel errorсѓњтђІтѕЦсЂФтѕцт«џ
func (h *JobHandler) CreateJob(w http.ResponseWriter, r *http.Request) {
    err := h.createJob.Execute(r.Context(), input)
    if err != nil {
        if errors.Is(err, model.ErrTaskAlreadyRunning) {
            writeJSON(w, http.StatusConflict, ErrorResponse{Message: err.Error()})
            return
        }
        if errors.Is(err, model.ErrInvalidCSVFormat) {
            writeJSON(w, http.StatusBadRequest, ErrorResponse{Message: err.Error()})
            return
        }
        if errors.Is(err, model.ErrDuplicateEmail) {
            writeJSON(w, http.StatusBadRequest, ErrorResponse{Message: err.Error()})
            return
        }
        // ... sentinel errorсЂ«ТЋ░сЂасЂЉifТќЄсЂїтбЌсЂѕсѓІ
        writeJSON(w, http.StatusInternalServerError, ErrorResponse{Message: "тєЁжЃесѓесЃЕсЃ╝сЂїуЎ║ућЪсЂЌсЂЙсЂЌсЂЪ"})
        return
    }
}
```

sentinel errorсЂїтбЌсЂѕсѓІсЂЪсЂ│сЂФHandlerт▒цсЂ«ifТќЄсЂїтбЌТ«ќсЂЌсЂЙсЂЎсђѓ**сѓесЃЕсЃ╝сЂ«уе«жАъсЂеHTTPсѓ╣сЃєсЃ╝сѓ┐сѓ╣сЂ«т»Йт┐юсЂїТЋБтюе**сЂЌсЂдсЂЌсЂЙсЂёсЂЙсЂЌсЂЪсђѓ

