func isDuplicateKeyError(err error) bool {
	if err == nil {
		return false
	}
	// PostgreSQL duplicate key error code is 23505
	errString := err.Error()
	return strings.Contains(errString, "23505") ||
		strings.Contains(errString, "duplicate key") ||
		strings.Contains(errString, "UNIQUE constraint failed")
}

