// CreateImportJob handles POST /v1/users/bulk-import requests.
func (h *ImportJobHandler) CreateImportJob(c *gin.Context) {
	// Get file from multipart form
	file, header, err := c.Request.FormFile("file")
	if err != nil {
		h.respondError(c, http.StatusBadRequest, "MISSING_FILE", "CSVсЃЋсѓАсѓцсЃФсЂїт┐ЁУдЂсЂДсЂЎ")
		return
	}
	defer func() {
		if err := file.Close(); err != nil {
			h.logger.WarnContext(c.Request.Context(), "Failed to close uploaded file", slog.String("error", err.Error()))
		}
	}()

	// Check file size
	if header.Size > MaxFileSize {
		h.respondError(c, http.StatusBadRequest, "FILE_TOO_LARGE", "сЃЋсѓАсѓцсЃФсѓхсѓцсѓ║сЂ»ТюђтцД5MBсЂДсЂЎ")
		return
	}

	// Read file content
	csvData, err := io.ReadAll(file)
	if err != nil {
		h.logger.ErrorContext(c.Request.Context(), "Failed to read file",
			slog.String("error", err.Error()))
		h.respondError(c, http.StatusInternalServerError, "INTERNAL_ERROR", "сЃЋсѓАсѓцсЃФсЂ«УфГсЂ┐тЈќсѓісЂФтц▒ТЋЌсЂЌсЂЙсЂЌсЂЪ")
		return
	}

	// Get optional webhook URL
	var webhookURL *string
	if url := c.PostForm("webhook_url"); url != "" {
		webhookURL = &url
	}

	// Create import job
	req := &input.CreateImportJobRequest{
		CSVData:    string(csvData),
		WebhookURL: webhookURL,
	}

	resp, err := h.createJobUseCase.Execute(c.Request.Context(), req)
	if err != nil {
		h.handleError(c, err)
		return
	}

	c.JSON(http.StatusAccepted, mapper.ToCreateImportJobResponse(resp))
}

