### тцЅТЈЏсЂЎсЂ╣сЂЇсЂДсЂфсЂёсѓ▒сЃ╝сѓ╣

СИђТќ╣сђЂ**сЃЊсѓИсЃЇсѓ╣тѕцТќГсѓњС╝┤сЂєтцЅТЈЏ**сЂ»сѓцсЃ│сЃЋсЃЕт▒цсЂДУАїсЂєсЂ╣сЂЇсЂДсЂ»сЂѓсѓісЂЙсЂЏсѓЊсђѓ

```go
// РЮї сѓцсЃ│сЃЋсЃЕт▒цсЂДсЃЊсѓИсЃЇсѓ╣тѕцТќГсѓњсЂЌсЂдсЂёсѓІ
func (r *userRepository) Save(ctx context.Context, u *model.User) error {
    result := r.db.Create(r.toDBModel(u))
    if result.Error != nil {
        if isDuplicateKeyError(result.Error) {
            return apperror.ErrDuplicateEntry  // сЃЊсѓИсЃЇсѓ╣тѕцТќГ Рєњ InteractorсЂ«У▓гтІЎ
        }
        return result.Error
    }
    return nil
}
```

сђїСИђТёЈтѕХу┤ёжЂЋтЈЇ Рєњ жЄЇУцЄсѓесЃ│сЃѕсЃфсѓесЃЕсЃ╝сђЇсЂ»сЃЊсѓИсЃЇсѓ╣тѕцТќГсЂДсЂЎсђѓтљїсЂўСИђТёЈтѕХу┤ёжЂЋтЈЇсЂДсѓѓсђЂТќЄУёѕсЂФсѓѕсЂБсЂдсђїсЃАсЃ╝сЃФсѓбсЃЅсЃгсѓ╣сЂ«жЄЇУцЄсђЇсЂфсЂ«сЂІсђїсѓИсЃДсЃќIDсЂ«жЄЇУцЄсђЇсЂфсЂ«сЂІТёЈтЉ│сЂїтцЅсѓЈсѓісЂЙсЂЎсђѓсЂЊсЂ«тѕцТќГсЂ»Interactorт▒цсЂДУАїсЂєсЂ╣сЂЇсЂДсЂЎсђѓ

