        C1[404 Not Found]
        C2[409 Conflict]
        C3[400 Bad Request]
        C4[500 Internal Error<br/>сЃГсѓ░Уеўжї▓сђЂУЕ│у┤░сЂ»жЮътЁгжќІ]
    end

    A1 --> B1 --> C1
    A2 --> B2 --> C2
    B3 --> C3
    INF[DBТјЦуХџсѓесЃЕсЃ╝<br/>сѓцсЃ│сЃЋсЃЕсѓесЃЕсЃ╝] --> B4 --> C4
```

