## сѓцсЃ│сЃЋсЃЕт▒цсЂДсЂ«сѓесЃЕсЃ╝тцЅТЈЏ

### ТЋЎуДЉТЏИсЂ«СИ╗т╝хсЂет«ЪтІЎсЂ«сѓ«сЃБсЃЃсЃЌ

сѓ»сЃфсЃ╝сЃ│сѓбсЃ╝сѓГсЃєсѓ»сЃЂсЃБсЂ«УДБУфгсЂДсЂ»сђїсѓцсЃ│сЃЋсЃЕт▒цсЂ»сѓцсЃ│сЃЋсЃЕсѓесЃЕсЃ╝сѓњсЂЮсЂ«сЂЙсЂЙУ┐ћсЂЌсђЂсѓбсЃЌсЃфсѓ▒сЃ╝сѓисЃДсЃ│т▒цсЂДУДБжЄѕсЂЎсЂ╣сЂЇсђЇсЂеУ┐░сЂ╣сѓЅсѓїсѓІсЂЊсЂесЂїсЂѓсѓісЂЙсЂЎсђѓсЂЌсЂІсЂЌт«ЪтІЎсЂДсЂ»**сѓцсЃ│сЃЋсЃЕт▒цсЂДDBсѓесЃЕсЃ╝сѓњсЃЅсЃАсѓцсЃ│сѓесЃЕсЃ╝сЂФтцЅТЈЏсЂЎсѓІ**сЃЉсѓ┐сЃ╝сЃ│сЂїТюЅті╣сЂДсЂЎсђѓ

```go
// infrastructure/postgres/job_repository.go
func (r *jobRepository) FindByID(ctx context.Context, id string) (*model.ImportJob, error) {
    var dest jobRow
    result := r.db.Where("id = ?", id).First(&dest)
    if result.Error != nil {
        if errors.Is(result.Error, gorm.ErrRecordNotFound) {
            return nil, model.ErrTaskNotFound  // сЃЅсЃАсѓцсЃ│сЂ«sentinel errorсЂФтцЅТЈЏ
        }
        return nil, fmt.Errorf("failed to find job: %w", result.Error)
    }
    return r.toDomainModel(&dest), nil
}
```

`gorm.ErrRecordNotFound`сѓњ`model.ErrTaskNotFound`сЂФтцЅТЈЏсЂЌсЂдсЂёсЂЙсЂЎсђѓсЂЊсѓїсѓњсђїсѓбсЃ│сЃЂсЃЉсѓ┐сЃ╝сЃ│сђЇсЂетЉ╝сЂХУеўС║ІсѓѓсЂѓсѓісЂЙсЂЎсЂїсђЂуДЂсЂ»**тбЃуЋїсЂДсЂ«у┐╗Уе│сЂесЂЌсЂдтљѕуљєуџё**сЂасЂеУђЃсЂѕсЂдсЂёсЂЙсЂЎсђѓ

сЂЪсЂасЂЌсђЂсЂЊсЂ«тцЅТЈЏсЃГсѓИсЃЃсѓ»сЂ«сЃдсЃІсЃЃсЃѕсЃєсѓ╣сЃѕсЂФсЂ»DBсЂ«сЃбсЃЃсѓ»сѓёtestcontainersсЂїт┐ЁУдЂсЂФсЂфсѓІуѓ╣сЂ»уЋЎТёЈсЂЌсЂдсЂЈсЂасЂЋсЂёсђѓ

### сЂфсЂютбЃуЋїсЂДсЂ«тцЅТЈЏсЂїтљѕуљєуџёсЂІ

1. **InteractorсЂї`gorm`сЃЉсЃЃсѓ▒сЃ╝сѓИсѓњуЪЦсѓЅсЂџсЂФТИѕсѓђ** Рђћ InteractorсЂД`gorm.ErrRecordNotFound`сѓњтѕцт«џсЂЎсѓІсЂесђЂсѓцсЃ│сЃЋсЃЕУЕ│у┤░сЂИсЂ«СЙЮтГўсЂїућЪсЂЙсѓїсЂЙсЂЎсђѓ
2. **RepositoryсЂ»сЃЅсЃАсѓцсЃ│сЂесѓцсЃ│сЃЋсЃЕсЂ«тбЃуЋїсЂДсЂѓсѓІ** Рђћ Repository interfaceсЂ»domainт▒цсЂФт«џуЙЕсЂЋсѓїсЂдсЂёсЂЙсЂЎсђѓсЂЮсЂ«т«ЪУБЁсЂ»сђїсЃЅсЃАсѓцсЃ│сЂ«УеђУЉЅсЂФу┐╗Уе│сЂЌсЂдУ┐ћсЂЎсђЇУ▓гтІЎсѓњТїЂсЂБсЂдсЂёсЂЙсЂЎсђѓ

сЂфсЂісђЂсЂЊсЂ«УеГУеѕсЂДсЂ»сѓцсЃ│сЃЋсЃЕт▒цсЂїсЃЅсЃАсѓцсЃ│сЂ«sentinel error№╝ѕ`model.ErrTaskNotFound`№╝ЅсЂФСЙЮтГўсЂЌсЂЙсЂЎсђѓсЃЅсЃАсѓцсЃ│сЂ«сѓесЃЕсЃ╝сѓисЃ│сЃюсЃФсѓњтцЅТЏ┤сЂЎсѓІсЂесѓцсЃ│сЃЋсЃЕт▒цсЂФсѓѓТ│бтЈісЂЌсЂЙсЂЎсђѓсЂЪсЂасЂЌсђЂInfrastructureРєњDomainсЂ«Тќ╣тљЉсЂ»сѓ»сЃфсЃ╝сЃ│сѓбсЃ╝сѓГсЃєсѓ»сЃЂсЃБсЂ«СЙЮтГўТќ╣тљЉсЂесЂЌсЂдТГБсЂЌсЂёсЂЪсѓЂсђЂУе▒т«╣у»ётЏ▓сЂетѕцТќГсЂЌсЂЙсЂЌсЂЪсђѓ

### тцЅТЈЏсЂЎсЂ╣сЂЇсЂДсЂфсЂёсѓ▒сЃ╝сѓ╣

СИђТќ╣сђЂ**ТќЄУёѕсЂФсѓѕсЂБсЂдТёЈтЉ│сЂїтцЅсѓЈсѓІсѓесЃЕсЃ╝тцЅТЈЏ**сЂ»сѓцсЃ│сЃЋсЃЕт▒цсЂДУАїсЂєсЂ╣сЂЇсЂДсЂ»сЂѓсѓісЂЙсЂЏсѓЊсђѓ

```go
// РЮї сѓцсЃ│сЃЋсЃЕт▒цсЂДТќЄУёѕСЙЮтГўсЂ«тцЅТЈЏсѓњсЂЌсЂдсЂёсѓІ
func (r *genericRepository) Save(ctx context.Context, entity any) error {
    result := r.db.Create(entity)
    if result.Error != nil {
        if isDuplicateKeyError(result.Error) {
            // сЂЕсЂ«сЃдсЃІсЃ╝сѓ»сѓГсЃ╝сЂїУАЮуфЂсЂЌсЂЪсЂІСИЇТўј Рєњ сЃЊсѓИсЃЇсѓ╣тѕцТќГсЂїт┐ЁУдЂ
            return apperror.ErrDuplicateEntry
        }
        return result.Error
    }
    return nil
}
```

УцЄТЋ░сЂ«сЃдсЃІсЃ╝сѓ»сѓГсЃ╝сѓњТїЂсЂцсЃєсЃ╝сЃќсЃФсЂДсЂ»сђЂтљїсЂўСИђТёЈтѕХу┤ёжЂЋтЈЇсЂДсѓѓсђїсЃАсЃ╝сЃФсѓбсЃЅсЃгсѓ╣сЂ«жЄЇУцЄсђЇсЂфсЂ«сЂІсђїсѓИсЃДсЃќIDсЂ«жЄЇУцЄсђЇсЂфсЂ«сЂІТќЄУёѕсЂФсѓѕсЂБсЂдТёЈтЉ│сЂїтцЅсѓЈсѓісЂЙсЂЎсђѓсЂЊсЂ«сѓѕсЂєсЂфтѕцТќГсЂ»Interactorт▒цсЂДУАїсЂєсЂ╣сЂЇсЂДсЂЎсђѓ

### тцЅТЈЏта┤ТЅђсЂ«тѕцТќГтЪ║Т║ќ

сђїсЂЕсЂ«сѓесЃЕсЃ╝сѓњсЂЕсЂЊсЂДтцЅТЈЏсЂЎсѓІсЂІсђЇсЂ«тѕцТќГтЪ║Т║ќсѓњТўјТќЄтїќсЂЌсЂфсЂёсЂесђЂт▒ъС║║уџёсЂфтѕцТќГсЂФсЂфсѓісЂїсЂАсЂДсЂЎсђѓуДЂсЂ«сЃЌсЃГсѓИсѓДсѓ»сЃѕсЂДсЂ»ТгАсЂ«сЃФсЃ╝сЃФсѓњУеГсЂЉсЂЙсЂЌсЂЪсђѓ

| ТЮАС╗Х | тцЅТЈЏта┤ТЅђ | СЙІ |
| --- | --- | --- |
| сѓесЃЕсЃ╝сЂ«ТёЈтЉ│сЂї1т»Й1сЂДт»Йт┐юсЂЎсѓІ№╝ѕТќЄУёѕсЂФСЙЮтГўсЂЌсЂфсЂё№╝Ѕ | Repositoryт▒ц | сђїсЃгсѓ│сЃ╝сЃЅсЂфсЂЌсђЇРєњсђїсѓ┐сѓ╣сѓ»сЂїУдІсЂцсЂІсѓЅсЂфсЂёсђЇ |
| сѓесЃЕсЃ╝сЂ«ТёЈтЉ│сЂїТќЄУёѕсЂДтцЅсѓЈсѓІ№╝ѕсЃЊсѓИсЃЇсѓ╣тѕцТќГсѓњС╝┤сЂє№╝Ѕ | Interactorт▒ц | сђїСИђТёЈтѕХу┤ёжЂЋтЈЇсђЇРєњсђїсЃАсЃ╝сЃФсѓбсЃЅсЃгсѓ╣жЄЇУцЄсђЇorсђїсѓИсЃДсЃќIDжЄЇУцЄсђЇ |
| ORM/DBтЏ║ТюЅсЂ«сѓесЃЕсЃ╝сЂДсђЂСИіСйЇт▒цсЂФС╝ЮсЂѕсѓІТёЈтЉ│сЂїсЂфсЂё | Repositoryт▒ц№╝ѕ`%w`сЂДсЃЕсЃЃсЃЌ№╝Ѕ | ТјЦуХџсѓесЃЕсЃ╝сђЂсѓ┐сѓцсЃасѓбсѓдсЃѕ |

`ExistsPendingOrProcessing`сЂ«сѓѕсЂєсЂФ**ТѕљтіЪ/тц▒ТЋЌсЂ«boolтђцсѓњУ┐ћсЂЎсЃАсѓйсЃЃсЃЅ**сЂ»сђЂсђїУдІсЂцсЂІсѓЅсЂфсЂёсђЇсѓњсѓесЃЕсЃ╝сЂесЂЌсЂдТЅ▒сЂєта┤жЮбсЂїсЂѓсѓісЂЙсЂЏсѓЊсђѓDBТјЦуХџсѓесЃЕсЃ╝сЂфсЂЕсЂ«ТіђУАЊуџёсЂфжџют«│сЂасЂЉсЂї`error`сЂесЂЌсЂдУ┐ћсЂЋсѓїсѓІсЂЪсѓЂсђЂ`%w`сЂДсЃЕсЃЃсЃЌсЂЌсЂдСИіСйЇсЂФС╝ЮТњГсЂЋсЂЏсЂЙсЂЎсђѓ

Repositoryт▒цсЂДсЂ«тцЅТЈЏсЂ»тЅЇУ┐░сЂ«`FindByID`№╝ѕ`gorm.ErrRecordNotFound` Рєњ `model.ErrTaskNotFound`№╝ЅсЂїУЕ▓тйЊсЂЌсЂЙсЂЎсђѓInteractorт▒цсЂДсЂ«тцЅТЈЏсЂ»ТгАсЂ«сѓ│сЃ╝сЃЅсЂДсЂЎсђѓ

```go
// РюЁ сѓцсЃ│сЃЋсЃЕт▒цсЂ»С║Іт«ЪсѓњсЃЅсЃАсѓцсЃ│сЂ«УеђУЉЅсЂДУ┐ћсЂЎ
func (r *userRepository) Save(ctx context.Context, u *model.User) error {
    result := r.db.Create(r.toDBModel(u))
    if result.Error != nil {
        if isDuplicateKeyError(result.Error) {
            return model.ErrDuplicateEmail  // сЃЅсЃАсѓцсЃ│сЂ«sentinel errorсЂФтцЅТЈЏ
        }
        return fmt.Errorf("failed to save user: %w", result.Error)
    }
    return nil
}

// isDuplicateKeyError сЂ»DBсЃЅсЃЕсѓцсЃљтЏ║ТюЅсЂ«СИђТёЈтѕХу┤ёжЂЋтЈЇсѓњтѕцт«џсЂЌсЂЙсЂЎсђѓ
// PostgreSQLсЂ«та┤тљѕсђЂpgconn.PgError сЂ« Code сЂї "23505" сЂІсЂЕсЂєсЂІсЂДтѕцт«џсЂЌсЂЙсЂЎсђѓ
func isDuplicateKeyError(err error) bool {
    var pgErr *pgconn.PgError
    return errors.As(err, &pgErr) && pgErr.Code == "23505"
}
```

сЂЊсЂЊсЂДуќЉтЋЈсЂїућЪсЂЙсѓїсЂЙсЂЎсђѓтЅЇУ┐░сЂ«сђїсЃЊсѓИсЃЇсѓ╣тѕцТќГсѓњС╝┤сЂєтцЅТЈЏсЂ»сѓцсЃ│сЃЋсЃЕт▒цсЂДУАїсЂєсЂ╣сЂЇсЂДсЂ»сЂфсЂёсђЇсЂесЂёсЂєсЃФсЃ╝сЃФсЂФтЈЇсЂЌсЂдсЂёсѓІсѓѕсЂєсЂФУдІсЂѕсѓІсЂІсѓЅсЂДсЂЎсђѓ

сЂЊсЂ«СЙІсЂДсЂ»сђЂ`userRepository.Save`сЂ»**UserсѓесЃ│сЃєсѓБсЃєсѓБсЂ«С┐ЮтГў**сЂФуЅ╣тїќсЂЌсЂЪRepositoryсЂДсЂЎсђѓСИђТёЈтѕХу┤ёжЂЋтЈЇсЂїсђїсЃАсЃ╝сЃФсѓбсЃЅсЃгсѓ╣сЂ«жЄЇУцЄсђЇсѓњТёЈтЉ│сЂЎсѓІсЂЊсЂесЂ»сђЂсЂЊсЂ«RepositoryсЂ«ТќЄУёѕсЂДСИђТёЈсЂФТ▒║сЂЙсѓісЂЙсЂЎсђѓ`FindByID`сЂДсђїсЃгсѓ│сЃ╝сЃЅсЂфсЂЌ Рєњ сѓ┐сѓ╣сѓ»сЂїУдІсЂцсЂІсѓЅсЂфсЂёсђЇсЂФтцЅТЈЏсЂЎсѓІсЂ«сЂетљїсЂўсЂЈсђЂ**сѓесЃЕсЃ╝сЂ«ТёЈтЉ│сЂї1т»Й1сЂДт»Йт┐юсЂЎсѓІ**сѓ▒сЃ╝сѓ╣сЂДсЂЎсђѓ

СИђТќ╣сђЂТ▒јућеуџёсЂф`Save`сЃАсѓйсЃЃсЃЅсЂДУцЄТЋ░сЂ«сЃдсЃІсЃ╝сѓ»сѓГсЃ╝сЂїтГўтюесЂЌсђЂсЂЕсЂ«сѓГсЃ╝сЂїУАЮуфЂсЂЌсЂЪсЂІсЂФсѓѕсЂБсЂдсЃЊсѓИсЃЇсѓ╣СИісЂ«ТёЈтЉ│сЂїтцЅсѓЈсѓІта┤тљѕсЂ»сђЂInteractorт▒цсЂДтѕцТќГсЂЎсѓІсЂ╣сЂЇсЂДсЂЎсђѓ

```go
// РюЁ Interactorт▒цсЂДсЃЊсѓИсЃЇсѓ╣тѕцТќГсЂЎсѓІ№╝ѕУцЄТЋ░сЂ«сЃдсЃІсЃ╝сѓ»сѓГсЃ╝сЂїсЂѓсѓІта┤тљѕ№╝Ѕ
func (i *CreateUserInteractor) Execute(ctx context.Context, input *CreateUserInput) error {
    // С║ІтЅЇсЃЂсѓДсЃЃсѓ»сЂДсЃЊсѓИсЃЇсѓ╣тѕцТќГсѓњInteractorсЂФжЏєу┤ёсЂЎсѓІ
    exists, err := i.userRepo.ExistsByEmail(ctx, input.Email)
    if err != nil {
        return fmt.Errorf("failed to check email: %w", err)
    }
    if exists {
        return apperror.ErrDuplicateEntry  // CodedError
    }

    user := model.NewUser(input.Name, input.Email)
    if err := i.userRepo.Save(ctx, user); err != nil {
        return fmt.Errorf("failed to save user: %w", err)
    }
    return nil
}
```

сЂЊсЂ«Тќ╣Т│ЋсЂфсѓЅсђЂInteractorсЂ»сѓцсЃ│сЃЋсЃЕУЕ│у┤░№╝ѕ`pgconn.PgError`№╝ЅсЂФСЙЮтГўсЂЌсЂЙсЂЏсѓЊсђѓсЂЪсЂасЂЌсђЂС║ІтЅЇсЃЂсѓДсЃЃсѓ»сЂеС┐ЮтГўсЂ«жќЊсЂФсЃгсЃ╝сѓ╣сѓ│сЃ│сЃЄсѓБсѓисЃДсЃ│сЂїуЎ║ућЪсЂЎсѓІтЈ»УЃйТђДсЂїсЂѓсѓІсЂЪсѓЂсђЂсЃѕсЃЕсЃ│сѓХсѓ»сѓисЃДсЃ│сѓёсЃдсЃІсЃ╝сѓ»тѕХу┤ёсЂесЂ«СйхућесЂїт┐ЁУдЂсЂДсЂЎсђѓ

