## сЃЅсЃАсѓцсЃ│сѓесЃЕсЃ╝сЂеCodedErrorсЂ«Сй┐сЂётѕєсЂЉ

сЃЅсЃАсѓцсЃ│т▒цсЂДсЂ»sentinel errorсѓњСй┐сЂёсђЂсѓбсЃЌсЃфсѓ▒сЃ╝сѓисЃДсЃ│т▒ц№╝ѕInteractor№╝ЅсЂДCodedErrorсЂФтцЅТЈЏсЂЌсЂЙсЂЎсђѓ

```go
// domain/model/errors.go№╝ѕтцЅТЏ┤сЂфсЂЌ№╝Ѕ
var (
    ErrTaskAlreadyRunning = errors.New("another task is already running")
    ErrInvalidCSVFormat   = errors.New("invalid CSV format")
)
```

```go
// usecase/create_job_interactor.go
func (i *CreateJobInteractor) Execute(ctx context.Context, req *CreateJobInput) (*CreateJobOutput, error) {
    // сЃљсЃфсЃЄсЃ╝сѓисЃДсЃ│№╝ѕу░АуЋЦтїќсЂ«сЂЪсѓЂТ▒јућесѓесЃЕсЃ╝сѓњУ┐ћсЂЌсЂдсЂёсѓІ№╝Ѕ
    if err := i.validateInput(req); err != nil {
        return nil, apperror.ErrInvalidFormat  // CodedError
    }
    // NOTE: т«ЪжџЏсЂ«APIсЂДсЂ»сђїсЂЕсЂ«сЃЋсѓБсЃ╝сЃФсЃЅсЂїСИЇТГБсЂІсђЇсѓњсѓ»сЃЕсѓцсѓбсЃ│сЃѕсЂФУ┐ћсЂЎт┐ЁУдЂсЂїсЂѓсѓісЂЙсЂЎсђѓ
    // сЃЋсѓБсЃ╝сЃФсЃЅсЃгсЃЎсЃФсЂ«сЃљсЃфсЃЄсЃ╝сѓисЃДсЃ│сѓесЃЕсЃ╝сЂ» CodedError сѓњТІАт╝хсЂЌсЂд details сЃЋсѓБсЃ╝сЃФсЃЅсѓњ
    // ТїЂсЂЪсЂЏсѓІсЂІсђЂт░ѓућесЂ« ValidationError тъІсѓњт«џуЙЕсЂЎсѓІсЂ«сЂїт«ЪУихуџёсЂДсЂЎсђѓ

    // ТјњС╗ќсЃЂсѓДсЃЃсѓ»
    running, err := i.jobRepo.ExistsPendingOrProcessing(ctx)
    if err != nil {
        return nil, fmt.Errorf("failed to check running jobs: %w", err)  // сѓцсЃ│сЃЋсЃЕсѓесЃЕсЃ╝
    }
    if running {
        return nil, apperror.ErrAlreadyRunning  // CodedError
    }

    // сЃЅсЃАсѓцсЃ│сѓфсЃќсѓИсѓДсѓ»сЃѕућЪТѕљ
    job := model.NewImportJob(req.Data, req.WebhookURL)
    if err := i.jobRepo.Save(ctx, job); err != nil {
        return nil, fmt.Errorf("failed to save job: %w", err)  // сѓцсЃ│сЃЋсЃЕсѓесЃЕсЃ╝
    }

    return &CreateJobOutput{JobID: job.ID}, nil
}
```

### сЂфсЂюсЃЅсЃАсѓцсЃ│т▒цсЂ»sentinel errorсЂ«сЂЙсЂЙсЂфсЂ«сЂІ

сЃЅсЃАсѓцсЃ│т▒цсЂ»**HTTPсѓ╣сЃєсЃ╝сѓ┐сѓ╣сѓёсѓесЃЕсЃ╝сѓ│сЃ╝сЃЅсѓњуЪЦсѓІсЂ╣сЂЇсЂДсЂ»сЂфсЂё**сЂІсѓЅсЂДсЂЎсђѓсЃЅсЃАсѓцсЃ│сЂ«жќбт┐ЃС║ІсЂ»сђїсЃЊсѓИсЃЇсѓ╣сЃФсЃ╝сЃФжЂЋтЈЇсЂїУхисЂЇсЂЪсЂЊсЂесђЇсЂДсЂѓсѓісђЂHTTP 400сѓё409сЂИсЂ«тцЅТЈЏсЂ»сЃЌсЃгсѓ╝сЃ│сЃєсЃ╝сѓисЃДсЃ│сЂ«У▓гтІЎсЂДсЂЎсђѓ

```go
// usecase/get_job_interactor.go
func (i *GetJobInteractor) Execute(ctx context.Context, id string) (*GetJobOutput, error) {
    job, err := i.repo.FindByID(ctx, id)
    if err != nil {
        if errors.Is(err, model.ErrTaskNotFound) {
            return nil, apperror.ErrNotFound  // sentinel Рєњ CodedError
        }
        return nil, fmt.Errorf("failed to get job: %w", err)
    }
    return &GetJobOutput{Job: job}, nil
}
```

